fn focus_change_effect(focused: bool) -> PendingEffect<Machine> {
    PendingEffect::new(
        Effect::FocusChange,
        move |_ctx: &Context, props: &Props, _send| {
            if let Some(callback) = &props.on_focus_change {
                callback(focused);
            }

            no_cleanup()
        },
    )
}

