    }

    #[test]
    fn editable_activation_handlers_respect_activate_mode() {
        for (mode, invoke, should_activate) in [
            (
                ActivateMode::Click,
                Api::on_preview_click as fn(&Api<'_>),
                true,
            ),
            (
                ActivateMode::DblClick,
                Api::on_preview_dblclick as fn(&Api<'_>),
                true,
